13	interface RunScenarioOptions {
14	  onTestCaseStart?: (
15	    testCase: TestCase,
16	    testCaseIndex: number,
17	    totalTestCases: number
18	  ) => void | Promise<void>;
19	  onStepStart?: (
20	    testCase: TestCase,
21	    testCaseIndex: number,
22	    step: AnyStep,
23	    stepIndex: number
24	  ) => void | Promise<void>;
25	  onStepComplete?: (
26	    testCase: TestCase,
27	    testCaseIndex: number,
28	    result: StepResult,
29	    stepIndex: number,
30	    executedStepCount: number
31	  ) => void | Promise<void>;
32	  onTestCaseComplete?: (
33	    testCase: TestCase,
34	    testCaseIndex: number,
35	    result: TestCaseResult
36	  ) => void | Promise<void>;
37	}
