39	async function runTestCase(
40	  testCase: TestCase,
41	  executor: PlaywrightExecutor | AndroidExecutor,
42	  scenarioDbConfig?: TiberoConfig,
43	  options: Omit<RunScenarioOptions, "onTestCaseStart" | "onTestCaseComplete"> = {},
44	  testCaseIndex = 0
45	): Promise<TestCaseResult> {
46	  const dbConfig = testCase.dbConfig ?? scenarioDbConfig;
47	  const startedAt = Date.now();
48	
49	  const stepResults = await executor.executeSteps(
50	    testCase.steps,
51	    dbConfig,
52	    {
53	      onStepStart: (step, stepIndex) =>
54	        options.onStepStart?.(testCase, testCaseIndex, step, stepIndex),
55	      onStepComplete: (result, stepIndex, executedStepCount) =>
56	        options.onStepComplete?.(testCase, testCaseIndex, result, stepIndex, executedStepCount),
57	    },
58	    testCase.baseUrl || undefined
59	  );
60	  const hasError = stepResults.some((result) => result.status === "error");
61	
62	  return {
63	    testCaseId: testCase.id,
64	    testCaseName: testCase.name,
65	    status: hasError ? "error" : "passed",
66	    executionTime: Date.now() - startedAt,
67	    stepResults,
68	  };
69	}
70	
71	export async function runScenario(
72	  scenario: Scenario,
73	  options: RunScenarioOptions = {}
74	): Promise<ScenarioResult> {
75	  const testCaseResults: TestCaseResult[] = [];
76	  const executor =
77	    scenario.platform === "android" ? new AndroidExecutor() : new PlaywrightExecutor();
78	
79	  try {
80	    await executor.initialize();
81	
82	    for (const [testCaseIndex, testCase] of scenario.testCases.entries()) {
83	      await options.onTestCaseStart?.(testCase, testCaseIndex, scenario.testCases.length);
84	      const result = await runTestCase(testCase, executor, scenario.dbConfig, options, testCaseIndex);
85	      testCaseResults.push(result);
86	      await options.onTestCaseComplete?.(testCase, testCaseIndex, result);
87	    }
88	  } finally {
89	    await executor.close();
90	  }
91	
92	  return {
93	    scenarioId: scenario.id,
94	    scenarioName: scenario.name,
95	    executedAt: new Date().toISOString(),
96	    testCaseResults,
97	  };
98	}
